import random
import time
import anthropic
from dataclasses import dataclass
from typing import Callable, Any


@dataclass
class ErrorConfig:
    max_retries: int = 3
    base_delay: float = 1.0      # seconds
    overload_base: float = 10.0  # 529 needs a longer pause
    cap: float = 60.0


_NON_RETRIABLE = (
    anthropic.AuthenticationError,
    anthropic.PermissionDeniedError,
    anthropic.BadRequestError,
    anthropic.NotFoundError,
    anthropic.UnprocessableEntityError,
)

_RETRIABLE = (
    anthropic.RateLimitError,
    anthropic.InternalServerError,
    anthropic.OverloadedError,
    anthropic.APIConnectionError,
    anthropic.APITimeoutError,
)


def _backoff(attempt: int, base: float, cap: float) -> float:
    return random.uniform(0, min(cap, base * (2 ** attempt)))


def call_with_classification(
    fn: Callable[[], Any],
    cfg: ErrorConfig = ErrorConfig(),
) -> Any:
    """
    Calls fn() with retry logic.
    Raises immediately for non-retriable errors.
    Exhausts retries for retriable errors, then re-raises.
    """
    for attempt in range(cfg.max_retries + 1):
        try:
            return fn()
        except _NON_RETRIABLE:
            raise  # never retry; fix the code, not the call
        except anthropic.RateLimitError as exc:
            if attempt == cfg.max_retries:
                raise
            # Honour the retry-after header if the API sent one
            retry_after = float(
                getattr(exc, "response", None)
                and exc.response.headers.get("retry-after", 0)
                or 0
            )
            delay = max(retry_after, _backoff(attempt, cfg.base_delay, cfg.cap))
            time.sleep(delay)
        except (anthropic.OverloadedError, anthropic.APIConnectionError, anthropic.APITimeoutError) as exc:
            if attempt == cfg.max_retries:
                raise
            time.sleep(_backoff(attempt, cfg.overload_base, cfg.cap))
        except anthropic.InternalServerError:
            if attempt == cfg.max_retries or attempt >= 3:
                raise
            time.sleep(_backoff(attempt, cfg.base_delay, cfg.cap))
    raise RuntimeError("unreachable")


# Usage
client = anthropic.Anthropic()
response = call_with_classification(
    lambda: client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role": "user", "content": "Hello"}],
    )
)

import threading
from functools import lru_cache


class CachedClaudeClient:
    def __init__(self, client: anthropic.Anthropic):
        self._client = client
        self._lock = threading.Lock()
        self._cache: dict[str, str] = {}  # cache_key → last successful text

    def generate(self, cache_key: str, **kwargs) -> str:
        try:
            response = call_with_classification(
                lambda: self._client.messages.create(**kwargs)
            )
            text = response.content[0].text
            with self._lock:
                self._cache[cache_key] = text
            return text
        except anthropic.APIError:
            with self._lock:
                fallback = self._cache.get(cache_key)
            if fallback is not None:
                return fallback  # stale but available
            raise  # no cache entry — propagate to the caller

_FALLBACK_CHAIN = [
    "claude-sonnet-4-6",
    "claude-haiku-4-5",  # fallback when Sonnet is overloaded
]


def create_with_model_fallback(client: anthropic.Anthropic, **kwargs):
    last_exc = None
    for model in _FALLBACK_CHAIN:
        try:
            return call_with_classification(
                lambda: client.messages.create(model=model, **kwargs)
            )
        except (anthropic.OverloadedError, anthropic.APIConnectionError) as exc:
            last_exc = exc
            continue  # try next model in chain
        except anthropic.APIError:
            raise  # non-retriable or rate limit: don't switch models
    raise last_exc

STATIC_FALLBACKS = {
    "product_description": "Our team is updating this description. Please check back shortly.",
    "recommendation": "We're personalising your recommendations. Default items shown below.",
}


def generate_or_fallback(feature: str, client: anthropic.Anthropic, **kwargs) -> str:
    try:
        response = call_with_classification(
            lambda: client.messages.create(**kwargs)
        )
        return response.content[0].text
    except anthropic.APIError as exc:
        import logging, json
        logging.getLogger("claude").warning(json.dumps({
            "event": "claude.fallback",
            "feature": feature,
            "error": type(exc).__name__,
        }))
        return STATIC_FALLBACKS.get(feature, "Content temporarily unavailable.")

import json
import time
from pathlib import Path


class DeadLetterQueue:
    def __init__(self, path: str = "dlq.jsonl"):
        self._path = Path(path)

    def enqueue(self, payload: dict, error: Exception):
        entry = {
            "ts": time.time(),
            "error_type": type(error).__name__,
            "error": str(error),
            "payload": payload,
        }
        with self._path.open("a") as f:
            f.write(json.dumps(entry) + "\n")

    def drain(self, handler):
        if not self._path.exists():
            return
        lines = self._path.read_text().splitlines()
        remaining = []
        for line in lines:
            entry = json.loads(line)
            try:
                handler(entry["payload"])
            except anthropic.APIError:
                remaining.append(line)
        if remaining:
            self._path.write_text("\n".join(remaining) + "\n")
        else:
            self._path.unlink()


dlq = DeadLetterQueue()


def process_item(payload: dict):
    try:
        call_with_classification(
            lambda: client.messages.create(**payload["kwargs"])
        )
    except anthropic.APIError as exc:
        dlq.enqueue(payload, exc)
